import { describe, it, expect, vi } from 'vitest';
import { formatDate } from './formatDate';

describe('formatDate', () => {
  it('should handle happy path with a valid ISO date string', () => {
    const isoString = '2023-07-21T14:35:00Z';
    const result = formatDate(isoString);
    // Assuming the function formats to a human readable string like 'Jul 21, 2023'
    expect(result).toBe('Jul 21, 2023');
  });

  it('should handle edge case with leap year date string', () => {
    const isoString = '2024-02-29T10:00:00Z';
    const result = formatDate(isoString);
    // Expected format for leap day
    expect(result).toBe('Feb 29, 2024');
  });

  it('should handle null/empty inputs correctly', () => {
    // Test null input
    expect(formatDate(null as unknown as string)).toBeUndefined();

    // Test undefined input
    expect(formatDate(undefined as unknown as string)).toBeUndefined();

    // Test empty string
    expect(formatDate('')).toBeUndefined();

    // Test zero value
    expect(formatDate('0' as unknown as string)).toBeUndefined();
  });
});

