import { describe, it, expect } from 'vitest';

describe('truncateContent', () => {
  // Helper to import the function; adjust the path as needed
  const { truncateContent } = await import('../../src/truncateContent');

  it('should handle happy path with content shorter than maxLength', () => {
    const content = 'Hello world!';
    const result = truncateContent(content, 20);
    expect(result).toBe('Hello world!');
  });

  it('should handle edge case where content length equals maxLength', () => {
    const content = 'A'.repeat(10);
    const result = truncateContent(content, 10);
    expect(result).toBe('A'.repeat(10));
  });

  it('should handle null/empty values gracefully', () => {
    expect(truncateContent(null as any, 10)).toBe('');
    expect(truncateContent(undefined as any, 10)).toBe('');
    expect(truncateContent('', 10)).toBe('');
    expect(truncateContent(0 as any, 10)).toBe('');
  });
});

